 1→import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
 2→
 3→let client;
 4→
 5→function getClient() {
 6→  if (!client) {
 7→    client = new S3Client({
 8→      endpoint: process.env.S3_ENDPOINT,
 9→      region: process.env.S3_REGION ?? 'auto',
10→      credentials: {
11→        accessKeyId: process.env.S3_ACCESS_KEY,
12→        secretAccessKey: process.env.S3_SECRET_KEY,
13→      },
14→      forcePathStyle: true,
15→    });
16→  }
17→  return client;
18→}
19→
20→const bucket = () => process.env.S3_BUCKET;
21→const key = (id) => `skills/${id}.md`;
22→
23→export async function putSkill(id, content) {
24→  await getClient().send(new PutObjectCommand({
25→    Bucket: bucket(),
26→    Key: key(id),
27→    Body: content,
28→    ContentType: 'text/markdown',
29→  }));
30→}
31→
32→export async function getSkill(id) {
33→  try {
34→    const response = await getClient().send(new GetObjectCommand({
35→      Bucket: bucket(),
36→      Key: key(id),
37→    }));
38→    return await response.Body.transformToString();
39→  } catch (err) {
40→    if (err.name === 'NoSuchKey' || err.$metadata?.httpStatusCode === 404) {
41→      return null;
42→    }
43→    throw err;
44→  }
45→}
