 1→import { updateStage, putSkill, markFailed } from '../storage.js';
 2→import { runResearch } from './research.js';
 3→import { runGenerate } from './generate.js';
 4→import { runValidate } from './validate.js';
 5→
 6→const MAX_RETRIES = 2;
 7→
 8→/**
 9→ * Run the full 3-stage generation pipeline for a skill.
10→ *
11→ * @param {string} skillId - UUID for the skill (S3 key)
12→ * @param {string} contractAddress - contract address to generate skill for
13→ * @param {number} chainId - chain ID (e.g. 8453 for Base Mainnet)
14→ * @param {string} [message] - optional user message / extra context
15→ */
16→export async function runPipeline(skillId, contractAddress, chainId, message) {
17→  let retries = 0;
18→
19→  try {
20→    // Stage 1: Research
21→    await updateStage(skillId, 'research');
22→
23→    const research = await runResearch(contractAddress, chainId);
24→
25→    if (research.abiAvailable === false) {
26→      throw new Error('Contract ABI is not available — skill generation cannot proceed');
27→    }
28→
29→    // Stage 2: Generate
30→    await updateStage(skillId, 'generate');
31→
32→    let skillContent = await runGenerate(research);
33→
34→    // Stage 3: Validate (with retry loop)
35→    await updateStage(skillId, 'validate');
36→
37→    let validation = await runValidate(skillContent, research.abi || []);
38→
39→    while (!validation.valid && retries < MAX_RETRIES) {
40→      retries++;
41→
42→      // Retry: generate with feedback, then re-validate
43→      await updateStage(skillId, 'generate');
44→      skillContent = await runGenerate(research, validation.errors);
45→
46→      await updateStage(skillId, 'validate');
47→      validation = await runValidate(skillContent, research.abi || []);
48→    }
49→
50→    if (!validation.valid) {
51→      throw new Error(`Validation failed after ${MAX_RETRIES} retries: ${validation.errors.join('; ')}`);
52→    }
53→
54→    // Store final skill with status: ready
55→    const finalContent = markReady(skillContent);
56→    await putSkill(skillId, finalContent);
57→
58→  } catch (err) {
59→    await markFailed(skillId, err.message);
60→    throw err;
61→  }
62→}
63→
64→/**
65→ * Update the status frontmatter field to "ready" in a SKILL.md.
66→ */
67→function markReady(content) {
68→  // If frontmatter exists, add/update status; otherwise prepend it
69→  if (/^---\n/.test(content)) {
70→    if (/^status:/m.test(content)) {
71→      return content.replace(/^status:.*$/m, 'status: "ready"');
72→    }
73→    return content.replace(/^---\n/, '---\nstatus: "ready"\n');
74→  }
75→  return content;
76→}
