 1→import { Router } from 'express';
 2→import { paymentMiddleware, x402ResourceServer } from '@x402/express';
 3→import { ExactEvmScheme } from '@x402/evm/exact/server';
 4→import { HTTPFacilitatorClient } from '@x402/core/http';
 5→import { facilitator } from '@coinbase/x402';
 6→import { privateKeyToAccount } from 'viem/accounts';
 7→import { declareDiscoveryExtension } from '@x402/extensions/bazaar';
 8→import { createPlaceholder, getSkill } from '../storage.js';
 9→import { runPipeline } from '../pipeline/index.js';
10→
11→const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';
12→const NETWORK = 'eip155:8453'; // Base Mainnet
13→
14→function buildResourceServer() {
15→  const facilitatorClient = new HTTPFacilitatorClient(facilitator);
16→  return new x402ResourceServer(facilitatorClient).register(NETWORK, new ExactEvmScheme());
17→}
18→
19→function buildPaymentMiddleware(payToAddress) {
20→  return paymentMiddleware(
21→    {
22→      'POST /generate': {
23→        accepts: {
24→          scheme: 'exact',
25→          price: '$0.10',
26→          network: NETWORK,
27→          payTo: payToAddress,
28→        },
29→        description: 'Generate an Agent Skill for a smart contract ($0.10 USDC)',
30→        ...declareDiscoveryExtension({
31→          bodyType: 'json',
32→          input: { contractAddress: '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48' },
33→        }),
34→      },
35→      'GET /:id': {
36→        accepts: {
37→          scheme: 'exact',
38→          price: '$0.01',
39→          network: NETWORK,
40→          payTo: payToAddress,
41→        },
42→        description: 'Download a generated Agent Skill ($0.01 USDC)',
43→        ...declareDiscoveryExtension({}),
44→      },
45→    },
46→    buildResourceServer(),
47→  );
48→}
