50→export function createSkillsRouter() {
51→  const router = Router();
52→
53→  const privateKey = process.env.WALLET_PRIVATE_KEY;
54→  if (privateKey) {
55→    const account = privateKeyToAccount(privateKey);
56→    router.use(buildPaymentMiddleware(account.address));
57→  }
58→
59→  // POST /skills/generate
60→  router.post('/generate', async (req, res) => {
61→    const { contractAddress, chainId, message } = req.body ?? {};
62→
63→    if (!contractAddress || chainId == null) {
64→      return res.status(400).json({ error: 'contractAddress and chainId are required' });
65→    }
66→
67→    const id = crypto.randomUUID();
68→    const url = `${BASE_URL}/skills/${id}`;
69→
70→    await createPlaceholder(id, { contractAddress, chainId });
71→
72→    runPipeline(id, contractAddress, chainId, message).catch(err => {
73→      console.error(`Pipeline failed for skill ${id}:`, err);
74→    });
75→
76→    return res.json({ id, url });
77→  });
78→
79→  // GET /skills/:id
80→  router.get('/:id', async (req, res) => {
81→    const { id } = req.params;
82→
83→    const skill = await getSkill(id);
84→    if (!skill) return res.status(404).json({ error: 'Skill not found' });
85→    return res.type('text/markdown').send(skill);
86→  });
87→
88→  return router;
89→}
