11→/**
12→ * Run the research stage for a smart contract.
13→ * @param {string} contractAddress
14→ * @param {number} chainId
15→ * @returns {Promise<object>} structured research summary
16→ */
17→export async function runResearch(contractAddress, chainId) {
18→  const { text } = await generateText({
19→    model,
20→    system: SYSTEM_PROMPT,
21→    prompt: `Research the smart contract at address ${contractAddress} on chain ${chainId}. Use the tools to fetch the ABI, source code, and detect ERC patterns. Then return a JSON object with your findings.`,
22→    tools: researchTools,
23→    maxSteps: 10,
24→  });
25→
26→  // Extract JSON from the response text
27→  const jsonMatch = text.match(/\{[\s\S]*\}/);
28→  if (!jsonMatch) {
29→    throw new Error(`Research stage did not return valid JSON. Response: ${text.slice(0, 200)}`);
30→  }
31→
32→  const summary = JSON.parse(jsonMatch[0]);
33→  return {
34→    contractAddress,
35→    chainId,
36→    ...summary,
37→  };
38→}
