10→/**
11→ * Run the generate stage to produce a SKILL.md.
12→ * @param {object} research - structured research summary from runResearch
13→ * @param {string[]} [validationErrors] - errors from previous validation attempt (for retries)
14→ * @returns {Promise<string>} SKILL.md content
15→ */
16→export async function runGenerate(research, validationErrors = []) {
17→  let prompt = `Generate a complete SKILL.md for the following smart contract research:\n\n${JSON.stringify(research, null, 2)}`;
18→
19→  if (validationErrors.length > 0) {
20→    prompt += `\n\nIMPORTANT: The previous generation attempt failed validation with these errors. Fix all of them:\n${validationErrors.map((e) => `- ${e}`).join('\n')}`;
21→  }
22→
23→  const { text } = await generateText({
24→    model,
25→    system: SYSTEM_PROMPT,
26→    prompt,
27→  });
28→
29→  return text.trim();
30→}
