 1→const EXPLORER_URLS = {
 2→  8453: 'https://api.basescan.org/api',
 3→  84532: 'https://api-sepolia.basescan.org/api',
 4→};
 5→
 6→function getExplorerUrl(chainId) {
 7→  const url = EXPLORER_URLS[chainId];
 8→  if (!url) throw new Error(`Unsupported chainId: ${chainId}`);
 9→  return url;
10→}
