12→export async function fetchABI(contractAddress, chainId) {
13→  const baseUrl = getExplorerUrl(chainId);
14→  const apiKey = process.env.ETHERSCAN_API_KEY;
15→  const url = `${baseUrl}?module=contract&action=getabi&address=${contractAddress}&apikey=${apiKey}`;
16→
17→  const res = await fetch(url);
18→  const data = await res.json();
19→
20→  if (data.status !== '1' || !data.result) return null;
21→  try {
22→    return JSON.parse(data.result);
23→  } catch {
24→    return null;
25→  }
26→}
27→
28→export async function fetchSourceCode(contractAddress, chainId) {
29→  const baseUrl = getExplorerUrl(chainId);
30→  const apiKey = process.env.ETHERSCAN_API_KEY;
31→  const url = `${baseUrl}?module=contract&action=getsourcecode&address=${contractAddress}&apikey=${apiKey}`;
32→
33→  const res = await fetch(url);
34→  const data = await res.json();
35→
36→  if (data.status !== '1' || !data.result?.[0]) return null;
37→  const sourceCode = data.result[0].SourceCode;
38→  return sourceCode || null;
39→}
